                x = sx
        else:
            if x > sx:
                steps += y // x
                y = y % x
                if y < sy:
                    if (sy - y) % x != 0:
                        return -1
                    steps += (sy - y) // x
                    y = sy
            else:
                if (y - sy) % x != 0:
                    return -1
                steps += (y - sy) // x
                y = sy
        if x < sx or y < sy:
            return -1
    return steps if x == sx and y == sy else -1
